const PROCESSING_FEE = 5;                          // constants: 1, bindings: 1
const FIRST_INSURANCE_RATE = 0.1;                  // constants: 1, bindings: 1

const BASE_PREMIUM: Record<string, number> = {     // bindings: 1, constants: 2 (100, 60)
  sword: 100, amulet: 60,                          
};

const itemPremium = (item: Item): number => {      // bindings: 2 (itemPremium, item)
  const base = BASE_PREMIUM[item.type];            // bindings: 1, invocations: 1 (index)
  return base + base * FIRST_INSURANCE_RATE;       // invocations: 2 (+, *)
};

const quotePremium = (step: QuoteStep): { premium: number } => {  // bindings: 2
  const itemsTotal = step.items.reduce((sum, item) => sum + itemPremium(item), 0);
  // bindings: 3 (itemsTotal, sum, item), invocations: 3 (reduce, +, itemPremium), constants: 1 (0), loops: 1
  return { premium: itemsTotal + PROCESSING_FEE }; // invocations: 1 (+)
};

export const run = (input: Input): { results: unknown[] } => {  // bindings: 2
  return { results: input.steps.map(quotePremium) };  // invocations: 1, loops: 1
};
